UPDATE coupon SET
    status        = #{status},
    reject_reason = #{memo, jdbcType=VARCHAR}
WHERE coupon_id = #{couponId}

mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, t.* FROM ( SELECT mc.member_coupon_id AS memberCouponId, mc.coupon_id AS couponId, c.coupon_name AS couponName, c.partner_id AS partnerId, p.partner_name AS partnerName, mc.member_id AS memberId, c.discount_type AS discountType, c.discount_amount AS discountAmount, mc.issued_at AS issuedAt, c.valid_until AS validUntil, mc.expired_at AS expiredAt, mc.status FROM member_coupon mc JOIN coupon c ON mc.coupon_id = c.coupon_id LEFT JOIN partner p ON c.partner_id = p.partner_id
AND mc.status = #{status}
AND c.coupon_name LIKE '%' || #{couponKeyword} || '%'
AND mc.member_id = #{memberKeyword}
ORDER BY mc.issued_at DESC ) t WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

SELECT COUNT(*)
FROM member_coupon mc
JOIN coupon c ON mc.coupon_id = c.coupon_id


        AND mc.status = #{status}


        AND c.coupon_name LIKE '%' || #{couponKeyword} || '%'


        AND mc.member_id = #{memberKeyword}

SELECT COUNT(*)
FROM member
WHERE status = 'ACTIVE'



            AND (SYSDATE - created_at) <= #{conditionValue}



        AND (
            SELECT COUNT(*)
            FROM reservation r
            WHERE r.member_id = member.member_id
              AND r.status = 'COMPLETED'
        ) >= #{conditionValue}


        AND (
            SELECT COUNT(*)
            FROM review rv
            WHERE rv.member_id = member.member_id
        ) >= #{conditionValue}


        AND (
            SELECT NVL(SUM(r.total_price), 0)
            FROM reservation r
            WHERE r.member_id = member.member_id
              AND r.status = 'COMPLETED'
        ) >= #{conditionValue}

SELECT member_id
FROM member1
WHERE status = '1'






            AND (SYSDATE - created_at) <= #{conditionValue}



        AND (
            SELECT COUNT(*) FROM reservation r
            WHERE r.member_id = member.member_id
              AND r.status = 'COMPLETED'
        ) >= #{conditionValue}


        AND (
            SELECT COUNT(*) FROM review rv
            WHERE rv.member_id = member.member_id
        ) >= #{conditionValue}


        AND (
            SELECT NVL(SUM(r.total_price), 0)
            FROM reservation r
            WHERE r.member_id = member.member_id
              AND r.status = 'COMPLETED'
        ) >= #{conditionValue}

SELECT
    CASE
        WHEN (SELECT COUNT(*) FROM coupon_target WHERE coupon_id = #{couponId}) = 0
             THEN 1
        WHEN (
            /* 포함 조건 매칭 체크 */
            SELECT COUNT(*) FROM coupon_target ct
            JOIN accommodation a ON a.place_id = #{accommodationPlaceId}
            LEFT JOIN place p    ON p.place_id = a.place_id
            WHERE ct.coupon_id   = #{couponId}
              AND ct.is_exclude  = 'N'
              AND (
                  (ct.target_type = 'ACCOMMODATION' AND ct.target_value = TO_CHAR(#{accommodationPlaceId}))
               OR (ct.target_type = 'ACC_TYPE'      AND ct.target_value = a.accommodation_type)
              )
        ) > 0
        AND (
            /* 제외 숙소 체크 */
            SELECT COUNT(*) FROM coupon_target
            WHERE coupon_id  = #{couponId}
              AND is_exclude = 'Y'
              AND target_type = 'ACCOMMODATION'
              AND target_value = TO_CHAR(#{accommodationPlaceId})
        ) = 0
        AND (
            /* 제외 객실 체크 */
            SELECT COUNT(*) FROM coupon_target
            WHERE coupon_id  = #{couponId}
              AND is_exclude = 'Y'
              AND target_type = 'ROOM'
              AND target_value = TO_CHAR(#{roomId})
        ) = 0
             THEN 1
        ELSE 0
    END AS applicable
FROM DUAL
